CREATE DATABASE IF NOT EXISTS `drive-learn-vw` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE `drive-learn-vw`;
CREATE TABLE unidades(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nome VARCHAR(120) NOT NULL,tipo ENUM('fabrica','assistencia','cliente') NOT NULL,cidade VARCHAR(80),uf CHAR(2),ativo BOOLEAN DEFAULT TRUE,criado_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE clientes(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,unidade_id BIGINT UNSIGNED,nome VARCHAR(160) NOT NULL,nome_fantasia VARCHAR(160),documento VARCHAR(20) UNIQUE,email VARCHAR(160),telefone VARCHAR(30),ativo BOOLEAN DEFAULT TRUE,criado_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(unidade_id) REFERENCES unidades(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE perfis(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nome VARCHAR(80) NOT NULL,slug VARCHAR(80) NOT NULL UNIQUE,escopo ENUM('global','unidade','cliente') DEFAULT 'cliente',ativo BOOLEAN DEFAULT TRUE) ENGINE=InnoDB;
CREATE TABLE permissoes(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,recurso VARCHAR(80) NOT NULL,acao ENUM('view','create','update','delete') NOT NULL,descricao VARCHAR(180),UNIQUE KEY uk_permissao(recurso,acao)) ENGINE=InnoDB;
CREATE TABLE perfil_permissoes(perfil_id BIGINT UNSIGNED NOT NULL,permissao_id BIGINT UNSIGNED NOT NULL,permitido BOOLEAN DEFAULT TRUE,PRIMARY KEY(perfil_id,permissao_id),FOREIGN KEY(perfil_id) REFERENCES perfis(id) ON DELETE CASCADE,FOREIGN KEY(permissao_id) REFERENCES permissoes(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE usuarios(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,perfil_id BIGINT UNSIGNED NOT NULL,unidade_id BIGINT UNSIGNED,cliente_id BIGINT UNSIGNED,nome VARCHAR(140) NOT NULL,email VARCHAR(180) NOT NULL UNIQUE,senha_hash VARCHAR(255) NOT NULL,ativo BOOLEAN DEFAULT TRUE,ultimo_acesso DATETIME,criado_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(perfil_id) REFERENCES perfis(id),FOREIGN KEY(unidade_id) REFERENCES unidades(id) ON DELETE SET NULL,FOREIGN KEY(cliente_id) REFERENCES clientes(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE notificacoes_lidas(usuario_id BIGINT UNSIGNED NOT NULL,notification_key VARCHAR(190) NOT NULL,lida_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(usuario_id,notification_key),FOREIGN KEY(usuario_id) REFERENCES usuarios(id) ON DELETE CASCADE,INDEX idx_notificacao_lida_data(lida_em)) ENGINE=InnoDB;
CREATE TABLE marcas(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nome VARCHAR(100) NOT NULL UNIQUE,slug VARCHAR(120) NOT NULL UNIQUE,logo VARCHAR(255),pais_origem VARCHAR(80),site_oficial VARCHAR(500),descricao TEXT,ativo BOOLEAN DEFAULT TRUE,criado_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP,atualizado_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB;
CREATE TABLE familias(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,marca_id BIGINT UNSIGNED NOT NULL,nome VARCHAR(100) NOT NULL,descricao TEXT,imagem VARCHAR(255),ativo BOOLEAN DEFAULT TRUE,criado_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP,UNIQUE KEY uk_familia_marca_nome(marca_id,nome),FOREIGN KEY(marca_id) REFERENCES marcas(id)) ENGINE=InnoDB;
CREATE TABLE modelos(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,familia_id BIGINT UNSIGNED NOT NULL,nome VARCHAR(120) NOT NULL,slug VARCHAR(140) NOT NULL UNIQUE,descricao TEXT,imagem VARCHAR(255),motor VARCHAR(120),potencia VARCHAR(100),torque VARCHAR(100),transmissao VARCHAR(140),pbt VARCHAR(80),especificacoes JSON,ativo BOOLEAN DEFAULT TRUE,criado_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(familia_id) REFERENCES familias(id)) ENGINE=InnoDB;
CREATE TABLE modelo_documentos(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,modelo_id BIGINT UNSIGNED NOT NULL,tipo ENUM('ficha_tecnica','diretriz_implementacao','manual','outro') NOT NULL DEFAULT 'ficha_tecnica',titulo VARCHAR(180) NOT NULL,arquivo VARCHAR(255),url_origem VARCHAR(700),fonte_pagina VARCHAR(700),ativo BOOLEAN DEFAULT TRUE,criado_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP,atualizado_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,UNIQUE KEY uk_modelo_documento_tipo(modelo_id,tipo),FOREIGN KEY(modelo_id) REFERENCES modelos(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE categorias(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,nome VARCHAR(120) NOT NULL UNIQUE,descricao TEXT,icone VARCHAR(80),imagem VARCHAR(255),ordem INT DEFAULT 0,ativo BOOLEAN DEFAULT TRUE) ENGINE=InnoDB;
CREATE TABLE subcategorias(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,categoria_id BIGINT UNSIGNED NOT NULL,nome VARCHAR(140) NOT NULL,descricao TEXT,imagem VARCHAR(255),ordem INT DEFAULT 0,ativo BOOLEAN DEFAULT TRUE,UNIQUE KEY uk_subcategoria_categoria_nome(categoria_id,nome),FOREIGN KEY(categoria_id) REFERENCES categorias(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE videos(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,categoria_id BIGINT UNSIGNED NOT NULL,subcategoria_id BIGINT UNSIGNED,titulo VARCHAR(180) NOT NULL,descricao TEXT,tipo ENUM('upload','youtube','vimeo','url') DEFAULT 'upload',arquivo_url VARCHAR(500) NOT NULL,thumbnail VARCHAR(255),duracao_segundos INT,status ENUM('rascunho','publicado','arquivado') DEFAULT 'rascunho',criado_por BIGINT UNSIGNED,publicado_em DATETIME,criado_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP,atualizado_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,FOREIGN KEY(categoria_id) REFERENCES categorias(id),FOREIGN KEY(subcategoria_id) REFERENCES subcategorias(id) ON DELETE SET NULL,FOREIGN KEY(criado_por) REFERENCES usuarios(id) ON DELETE SET NULL) ENGINE=InnoDB;
CREATE TABLE video_familias(video_id BIGINT UNSIGNED NOT NULL,familia_id BIGINT UNSIGNED NOT NULL,PRIMARY KEY(video_id,familia_id),FOREIGN KEY(video_id) REFERENCES videos(id) ON DELETE CASCADE,FOREIGN KEY(familia_id) REFERENCES familias(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE video_modelos(video_id BIGINT UNSIGNED NOT NULL,modelo_id BIGINT UNSIGNED NOT NULL,PRIMARY KEY(video_id,modelo_id),FOREIGN KEY(video_id) REFERENCES videos(id) ON DELETE CASCADE,FOREIGN KEY(modelo_id) REFERENCES modelos(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE frotas(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,cliente_id BIGINT UNSIGNED NOT NULL,marca_id BIGINT UNSIGNED NOT NULL,familia_id BIGINT UNSIGNED,modelo_id BIGINT UNSIGNED,veiculo_nome VARCHAR(160),familia_nome_livre VARCHAR(120),quantidade INT UNSIGNED DEFAULT 1,ano SMALLINT UNSIGNED,norma_emissao_id SMALLINT UNSIGNED,observacao TEXT,criado_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(cliente_id) REFERENCES clientes(id) ON DELETE CASCADE,FOREIGN KEY(marca_id) REFERENCES marcas(id),FOREIGN KEY(familia_id) REFERENCES familias(id),FOREIGN KEY(modelo_id) REFERENCES modelos(id)) ENGINE=InnoDB;
CREATE TABLE video_visualizacoes(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,video_id BIGINT UNSIGNED NOT NULL,usuario_id BIGINT UNSIGNED NOT NULL,iniciado_em DATETIME NOT NULL,concluido_em DATETIME,progresso_segundos INT UNSIGNED DEFAULT 0,percentual DECIMAL(5,2) DEFAULT 0,ip_hash CHAR(64),dispositivo VARCHAR(255),FOREIGN KEY(video_id) REFERENCES videos(id),FOREIGN KEY(usuario_id) REFERENCES usuarios(id),INDEX idx_visualizacao(video_id,usuario_id,concluido_em)) ENGINE=InnoDB;
CREATE TABLE feedbacks(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,visualizacao_id BIGINT UNSIGNED NOT NULL,nota TINYINT UNSIGNED NOT NULL,comentario TEXT,melhorias TEXT,criado_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP,UNIQUE KEY uk_feedback_visualizacao(visualizacao_id),CHECK(nota BETWEEN 1 AND 5),FOREIGN KEY(visualizacao_id) REFERENCES video_visualizacoes(id) ON DELETE CASCADE) ENGINE=InnoDB;
CREATE TABLE logs_auditoria(id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,usuario_id BIGINT UNSIGNED,acao VARCHAR(60) NOT NULL,entidade VARCHAR(80) NOT NULL,entidade_id BIGINT UNSIGNED,dados_anteriores JSON,dados_novos JSON,ip_hash CHAR(64),criado_em TIMESTAMP DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY(usuario_id) REFERENCES usuarios(id) ON DELETE SET NULL,INDEX idx_auditoria(entidade,entidade_id,criado_em)) ENGINE=InnoDB;
