INSERT INTO permissoes(recurso,acao,descricao) SELECT r.recurso,a.acao,CONCAT(a.acao,' em ',r.recurso) FROM (SELECT 'dashboard' recurso UNION SELECT 'library' UNION SELECT 'fleet' UNION SELECT 'brands' UNION SELECT 'families' UNION SELECT 'models' UNION SELECT 'categories' UNION SELECT 'subcategories' UNION SELECT 'videos' UNION SELECT 'clients' UNION SELECT 'users' UNION SELECT 'permissions' UNION SELECT 'reports' UNION SELECT 'feedback')r CROSS JOIN(SELECT 'view' acao UNION SELECT 'create' UNION SELECT 'update' UNION SELECT 'delete')a;
INSERT INTO perfil_permissoes(perfil_id,permissao_id) SELECT 1,id FROM permissoes;
INSERT INTO perfil_permissoes(perfil_id,permissao_id) SELECT 2,id FROM permissoes WHERE recurso<>'permissions' AND acao IN('view','create','update');
INSERT INTO perfil_permissoes(perfil_id,permissao_id) SELECT 3,id FROM permissoes WHERE(recurso IN('dashboard','library','fleet') AND acao='view')OR(recurso='fleet' AND acao IN('create','update','delete'))OR(recurso='feedback' AND acao='create');
